if (archive.ShowDialog() == true && !string.IsNullOrEmpty(archive.SelectedFile))
            {

                string path = Path.Combine(CurrentDir, "data", "comics");
                IEnumerable<string> dirs = Directory.EnumerateFiles(path, "*", SearchOption.AllDirectories);

                var result = Process.ExtractOne(archive.SelectedFile, dirs, s => Path.GetFileName(s));
                if (result != null && result.Score == 100)
                {
                    try
                    {
                        ImportWindows importWindows = new(JsonUtility.GetURLS(File.ReadAllText(result.Value)))
                        {
                            Owner = this,
                            Title = $"Import of {archive.SelectedFile}"
                        };

                        importWindows.Closed += (sender, e) => DeleteFile(path);
                        importWindows.Show();
                    }
                    catch (Exception ex)
                    {
                        MessageBox.Show($"Impossible d'importer le fichier : {ex.Message}", "Erreur", MessageBoxButton.OK, MessageBoxImage.Error);
                    }
                }
                else
                {
                    MessageBox.Show("Fichier sélectionné introuvable.", "Erreur", MessageBoxButton.OK, MessageBoxImage.Warning);
                }
            }

