public MainWindow()
        {
            InitializeComponent();

            InitFolder(Path.Combine(CurrentDir, "data"));
            InitFolder(Path.Combine(CurrentDir, "data", "backup"));
            InitFolder(Path.Combine(CurrentDir, "data", "comics"));

            if (File.Exists(BackupPath))
            {
                string backup = File.ReadAllText(BackupPath);
                var comics = JsonConvert.DeserializeObject<List<Comic>>(backup);
                if (comics is not null)
                {
                    foreach (var b in comics)
                        ComicUtility.comics.Add(b);
                }
            }
        }

